import React from 'react';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';

function Apropos() {
  const competences = [
    { nom: 'Réseaux & Systèmes', niveau: 80 },
    { nom: 'Cybersécurité / Kali Linux', niveau: 70 },
    { nom: 'Administration Linux', niveau: 75 },
    { nom: 'Windows Server / Active Directory', niveau: 72 },
    { nom: 'Création Web / WordPress', niveau: 60 },
  ];

  return (
    <div style={{background: '#000000', minHeight: '100vh', paddingTop: '100px'}}>

      {/* HEADER */}
      <motion.section
        initial={{opacity: 0, y: -30}}
        animate={{opacity: 1, y: 0}}
        transition={{duration: 0.8}}
        style={{
          textAlign: 'center', padding: '60px 20px',
          background: 'radial-gradient(ellipse at center, #0a1a0a 0%, #000000 70%)',
          borderBottom: '2px solid #00aa00'
        }}
      >
        <h1 style={{fontSize: '48px', color: '#ffd700', letterSpacing: '4px', marginBottom: '15px'}}>
          À propos de moi
        </h1>
        <p style={{color: '#aaaaaa', fontSize: '18px'}}>
          Ingénieur Réseaux & Systèmes passionné
        </p>
      </motion.section>

      {/* PRÉSENTATION */}
      <section style={{padding: '80px 50px', maxWidth: '1000px', margin: '0 auto'}}>
        <motion.div
          initial={{opacity: 0, x: -50}}
          whileInView={{opacity: 1, x: 0}}
          transition={{duration: 0.8}}
          style={{
            background: '#0a0a0a', border: '1px solid #00aa00',
            borderRadius: '15px', padding: '40px', marginBottom: '40px'
          }}
        >
          <h2 style={{color: '#ffd700', fontSize: '28px', marginBottom: '20px'}}>👤 Qui suis-je ?</h2>
          <p style={{color: '#cccccc', fontSize: '16px', lineHeight: '1.9', marginBottom: '15px'}}>
            Je suis Reve, ingénieur en réseaux et systèmes informatiques, titulaire d'un Master professionnel 
            obtenu à l'Institut Supérieur d'Informatique (ISI) de Dakar. Passionné par la cybersécurité 
            et les infrastructures IT, je propose des prestations sérieuses et adaptées à vos besoins.
          </p>
          <p style={{color: '#cccccc', fontSize: '16px', lineHeight: '1.9'}}>
            Dans le cadre de mon mémoire de fin d'études, j'ai travaillé sur l'analyse et la sécurisation 
            d'Active Directory Certificate Services (AD CS), ce qui m'a permis d'acquérir une expertise 
            solide en cybersécurité et en gestion des infrastructures Windows Server.
          </p>
        </motion.div>

        {/* COMPÉTENCES */}
        <motion.div
          initial={{opacity: 0, x: 50}}
          whileInView={{opacity: 1, x: 0}}
          transition={{duration: 0.8}}
          style={{
            background: '#0a0a0a', border: '1px solid #00aa00',
            borderRadius: '15px', padding: '40px', marginBottom: '40px'
          }}
        >
          <h2 style={{color: '#ffd700', fontSize: '28px', marginBottom: '30px'}}>⚡ Mes Compétences</h2>
          {competences.map((comp, i) => (
            <div key={i} style={{marginBottom: '20px'}}>
              <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '8px'}}>
                <span style={{color: '#cccccc', fontSize: '15px'}}>{comp.nom}</span>
                <span style={{color: '#00aa00', fontSize: '15px'}}>{comp.niveau}%</span>
              </div>
              <div style={{background: '#1a1a1a', borderRadius: '10px', height: '10px', overflow: 'hidden'}}>
                <motion.div
                  initial={{width: 0}}
                  whileInView={{width: `${comp.niveau}%`}}
                  transition={{duration: 1, delay: i * 0.2}}
                  style={{
                    height: '100%', borderRadius: '10px',
                    background: 'linear-gradient(90deg, #00aa00, #ffd700)'
                  }}
                />
              </div>
            </div>
          ))}
        </motion.div>

        {/* FORMATION */}
        <motion.div
          initial={{opacity: 0, y: 30}}
          whileInView={{opacity: 1, y: 0}}
          transition={{duration: 0.8}}
          style={{
            background: '#0a0a0a', border: '1px solid #00aa00',
            borderRadius: '15px', padding: '40px', marginBottom: '40px'
          }}
        >
          <h2 style={{color: '#ffd700', fontSize: '28px', marginBottom: '25px'}}>🎓 Formation</h2>
          <div style={{borderLeft: '3px solid #00aa00', paddingLeft: '20px'}}>
            <div style={{marginBottom: '25px'}}>
              <h3 style={{color: '#00aa00', fontSize: '18px', marginBottom: '5px'}}>
                Master Professionnel — Réseaux & Systèmes
              </h3>
              <p style={{color: '#aaaaaa', fontSize: '14px', marginBottom: '8px'}}>
                Institut Supérieur d'Informatique (ISI) — Dakar, Sénégal
              </p>
              <p style={{color: '#cccccc', fontSize: '14px'}}>
                Mémoire : Analyse, exploitation des vulnérabilités et stratégies de remédiation dans Active Directory Certificate Services.
              </p>
            </div>
          </div>
        </motion.div>

        {/* DISPONIBILITÉ */}
        <motion.div
          initial={{opacity: 0, y: 30}}
          whileInView={{opacity: 1, y: 0}}
          transition={{duration: 0.8}}
          style={{
            background: '#0a0a0a', border: '1px solid #ffd700',
            borderRadius: '15px', padding: '40px', textAlign: 'center'
          }}
        >
          <h2 style={{color: '#ffd700', fontSize: '28px', marginBottom: '25px'}}>🕐 Disponibilité</h2>
          <div style={{display: 'flex', justifyContent: 'center', gap: '40px', flexWrap: 'wrap'}}>
            <div>
              <p style={{color: '#00aa00', fontSize: '16px', marginBottom: '5px'}}>📍 Sur site — Dakar</p>
              <p style={{color: '#cccccc', fontSize: '14px'}}>Lundi — Vendredi : 08h00 - 18h00</p>
            </div>
            <div>
              <p style={{color: '#00aa00', fontSize: '16px', marginBottom: '5px'}}>🌐 À distance</p>
              <p style={{color: '#cccccc', fontSize: '14px'}}>Lundi — Samedi : Disponible à toute heure</p>
            </div>
          </div>
          <Link to="/contact" style={{
            display: 'inline-block', marginTop: '25px',
            background: '#00aa00', color: '#ffffff',
            padding: '12px 35px', borderRadius: '30px',
            textDecoration: 'none', fontSize: '15px', fontWeight: 'bold'
          }}>
            Me contacter
          </Link>
        </motion.div>
      </section>
    </div>
  );
}

export default Apropos;
